-- Patient index
CREATE INDEX IF NOT EXISTS patient_resource_idx ON Patient USING GIN (resource jsonb_path_ops);
CREATE INDEX IF NOT EXISTS patient_name_param_knife_string ON patient USING gin
      ((aidbox_text_search(knife_extract_text(resource,
      '[["name","family"],["name","given"],["name","middle"],["name","text"],["name","prefix"],["name","suffix"]]')))
      gin_trgm_ops);
CREATE INDEX IF NOT EXISTS patient_name_param_knife_string ON patient USING gin 
      ((knife_extract_text(resource,
      '[["name","family"],["name","given"],["name","middle"],["name","text"],["name","prefix"],["name","suffix"]]')));
CREATE INDEX IF NOT EXISTS patient_given_param_knife_string ON patient USING gin
      ((aidbox_text_search(knife_extract_text(resource, '[["name","given"]]'))) gin_trgm_ops);
CREATE INDEX IF NOT EXISTS patient_given_param_knife_string ON patient USING gin 
      ((knife_extract_text(resource, '[["name","given"]]')) );
CREATE INDEX IF NOT EXISTS patient_birthdate_param_knife_date_min_tstz ON patient USING btree
      ((knife_extract_min_timestamptz(resource, '[["birthDate"]]')) );
CREATE INDEX IF NOT EXISTS patient_birthdate_param_knife_date_max_tstz ON patient USING btree
      ((knife_extract_max_timestamptz(resource, '[["birthDate"]]')) );

